import React, { useState, useEffect, useRef } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
// import copy from "copy-to-clipboard";
import dayjs from "dayjs";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function SupportManagement() {
  const [supports, setSupports] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const [filters, setFilters] = useState({
    search: "",
    reqType: "",
    status: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const supportsPerPage = 10;

  const [formData, setFormData] = useState({
    id: null,
    description: "",
    status: "",
  });

  const editModalRef = useRef(null);
  const detailsModalRef = useRef(null);

  const [detailsSupport, setDetailsSupport] = useState(null);

  /* ================= FETCH SUPPORTS ================= */
  function fetchSupports() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/supports", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setSupports(res.data.data);
        } else {
          toast.error(res.data.error || "Failed to fetch supports");
        }
      })
      .catch((err) => {
        toast.error(err.response?.data?.error || "Error fetching supports");
      })
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchSupports();
  }, [navigate]);

  /* ================= FILTER ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  const filteredSupports = supports.filter((s) => {
    const searchMatch = filters.search
      ? (
          s.description +
          s.reqId +
          s.userFullName +
          s.employeeName
        )
          .toLowerCase()
          .includes(filters.search.toLowerCase())
      : true;

    return (
      searchMatch &&
      (filters.reqType ? s.reqType === filters.reqType : true) &&
      (filters.status ? s.status === filters.status : true)
    );
  });

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * supportsPerPage;
  const indexOfFirst = indexOfLast - supportsPerPage;
  const currentSupports = filteredSupports.slice(indexOfFirst, indexOfLast);
  const totalPages = Math.ceil(filteredSupports.length / supportsPerPage);

  /* ================= EDIT ================= */
  function handleEdit(support) {
    if (support.reqType !== "Followup") {
      toast.error("Main request cannot be edited");
      return;
    }

    setFormData({
      id: support.id,
      description: support.description,
      status: support.status,
    });

    const modal = new Modal(document.getElementById("editSupportModal"));
    editModalRef.current = modal;
    modal.show();
  }

  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    axios
      .put(API_BASE_URL + "/supports/" + formData.id, formData, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Followup updated successfully");
        fetchSupports();
        editModalRef.current.hide();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Update failed")
      );
  }

  /* ================= DELETE ================= */
  function handleDelete(support) {
    if (support.reqType !== "Followup") {
      toast.error("Main request cannot be deleted");
      return;
    }

    if (!window.confirm("Delete this followup?")) return;

    const token = Cookies.get("adminToken");

    axios
      .delete(API_BASE_URL + "/supports/" + support.id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Followup deleted");
        fetchSupports();
      })
      .catch((err) =>
        toast.error(err.response?.data?.error || "Delete failed")
      );
  }

  /* ================= DETAILS ================= */
  function openDetailsModal(support) {
    setDetailsSupport(support);
    const modal = new Modal(document.getElementById("detailsModal"));
    detailsModalRef.current = modal;
    modal.show();
  }

//   function handleCopy(text, type) {
//     if (copy(text)) toast.success(type + " copied");
//     else toast.error("Copy failed");
//   }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />

      <h4 className="fw-bold mb-3">Support Management</h4>

      {/* Filters */}
      <div className="row g-3 mb-3">
        <div className="col-md-4">
          <input
            type="text"
            name="search"
            className="form-control form-control-sm"
            placeholder="Search description / user / employee"
            value={filters.search}
            onChange={handleFilterChange}
          />
        </div>

        <div className="col-md-4">
          <select
            name="reqType"
            className="form-select form-select-sm"
            value={filters.reqType}
            onChange={handleFilterChange}
          >
            <option value="">Request Type</option>
            <option value="Main">Main</option>
            <option value="Followup">Followup</option>
          </select>
        </div>

        <div className="col-md-4">
          <select
            name="status"
            className="form-select form-select-sm"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">Status</option>
            <option value="In Progress">In Progress</option>
            <option value="Closed">Closed</option>
          </select>
        </div>
      </div>

      {/* Table */}
      <div className="card">
        {loading ? (
          <div className="text-center p-3">Loading...</div>
        ) : (
          <div className="table-responsive">
            <table className="table table-striped table-hover small">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>Type</th>
                  <th>Related User</th>
                  <th>Raised By</th>
                  <th>Status</th>
                  <th>Description</th>
                  <th>Date & Time</th>
                  <th>Actions</th>
                </tr>
              </thead>
<tbody>
  {currentGroups.map((group) => (
    <tr key={group.main.id}>
      <td>{group.main.id}</td>

      <td>
        <span className="badge bg-primary">Main</span>
      </td>

      <td>{group.main.userFullName}</td>

      <td>{group.main.employeeName}</td>

      <td>{group.main.status}</td>

      {/* Description Column with Thread */}
      <td style={{ minWidth: "350px" }}>
        {/* MAIN MESSAGE */}
        <div className="p-2 mb-2 bg-light border rounded">
          <strong>Main:</strong>
          <div>{group.main.description}</div>
          <small className="text-muted">
            {dayjs(group.main.createdAt).format(
              "DD MMM YYYY hh:mm A"
            )}
          </small>
        </div>

        {/* FOLLOWUPS */}
        {group.followups.map((f) => (
          <div
            key={f.id}
            className="p-2 mb-2 border rounded"
            style={{ backgroundColor: "#fff8dc" }}
          >
            <strong>Followup:</strong>
            <div>{f.description}</div>

            <small className="text-muted">
              {dayjs(f.createdAt).format(
                "DD MMM YYYY hh:mm A"
              )}
            </small>

            <div className="mt-1">
              <i
                className="fa-solid fa-pen text-primary me-2"
                style={{ cursor: "pointer" }}
                onClick={() => handleEdit(f)}
              ></i>

              <i
                className="fa-solid fa-trash text-danger"
                style={{ cursor: "pointer" }}
                onClick={() => handleDelete(f)}
              ></i>
            </div>
          </div>
        ))}

        {group.followups.length === 0 && (
          <small className="text-muted">
            No followups yet
          </small>
        )}
      </td>

      <td>
        {dayjs(group.main.updatedAt).format(
          "DD MMM YYYY hh:mm A"
        )}
      </td>

      <td>-</td>
    </tr>
  ))}
</tbody>

            </table>
          </div>
        )}
      </div>

      {/* Pagination */}
      <div className="d-flex justify-content-between mt-3">
        <div>
          Page {currentPage} of {totalPages}
        </div>
        <div>
          <button
            className="btn btn-sm btn-light me-2"
            disabled={currentPage === 1}
            onClick={() => setCurrentPage((p) => p - 1)}
          >
            Prev
          </button>
          <button
            className="btn btn-sm btn-light"
            disabled={currentPage === totalPages}
            onClick={() => setCurrentPage((p) => p + 1)}
          >
            Next
          </button>
        </div>
      </div>

      {/* Edit Modal */}
      <div className="modal fade" id="editSupportModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5>Edit Followup</h5>
                <button className="btn-close" data-bs-dismiss="modal"></button>
              </div>
              <div className="modal-body">
                <div className="mb-3">
                  <label>Status</label>
                  <select
                    className="form-select"
                    value={formData.status}
                    onChange={(e) =>
                      setFormData({
                        ...formData,
                        status: e.target.value,
                      })
                    }
                  >
                    <option value="In Progress">In Progress</option>
                    <option value="Closed">Closed</option>
                  </select>
                </div>
                <div className="mb-3">
                  <label>Description</label>
                  <textarea
                    className="form-control"
                    value={formData.description}
                    onChange={(e) =>
                      setFormData({
                        ...formData,
                        description: e.target.value,
                      })
                    }
                    required
                  />
                </div>
              </div>
              <div className="modal-footer">
                <button type="submit" className="btn btn-primary">
                  Update
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>

      {/* Details Modal */}
      <div className="modal fade" id="detailsModal" tabIndex="-1">
        <div className="modal-dialog modal-dialog-centered">
          <div className="modal-content p-3">
            {detailsSupport && (
              <>
                <h5>Description</h5>
                <p>{detailsSupport.description}</p>
                <hr />
                <p>
                  <strong>User:</strong>{" "}
                  {detailsSupport.userFullName}
                </p>
                <p>
                  <strong>Employee:</strong>{" "}
                  {detailsSupport.employeeName}
                </p>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}

export default SupportManagement;
